  ('pukao-0c700c30-moex-00098', 'pukao-0c700c30', 'pukao-0c700c30-moex-113-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '下列何者會創造對日元的需求？', '["日本學生到臺灣做交換生", "臺灣人前往日本北海道觀光", "臺灣機械業到泰國投資", "日本海鮮店進口屏東黑鮪魚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:48+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "419", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00099', 'pukao-0c700c30', 'pukao-0c700c30-moex-113-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '若GDP為國內生產毛額、GNP為國民生產毛額、C為民間消費、I為國內投資、G為政府購買，則淨出口 等於：', '["C+I+G-GNP", "GDP-C-I-G", "C+I+G-GDP", "GNP-C-I-G"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:48+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "419", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00100', 'pukao-0c700c30', 'pukao-0c700c30-moex-113-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '為提振景氣，某國政府擬發放消費券共計 10億元。依據該國政府的估算，其他條件不變之下，此一政策 總共可以提高該國國內生產毛額（GDP）5%。若該國目前的GDP為1,000億元，依據引入政府部門的簡 單凱因斯模型，該國政府估計該國的邊際消費傾向為何？', '["0.2", "0.6", "0.75", "0.8"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:48+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "419", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00101', 'pukao-0c700c30', 'pukao-0c700c30-moex-113-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '經濟不景氣，人們消費需求明顯減少，此時對產出與物價各有何影響？', '["產出下降、物價下降", "產出上升、物價上升", "產出下降、物價上升", "產出上升、物價下降"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:48+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "419", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00102', 'pukao-0c700c30', 'pukao-0c700c30-moex-113-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '假設不考慮國外部門與政府部門。在簡單凱因斯模型裡，如果民間消費函數為 C=10+0.8Y，則自發性支出 乘數等於：', '["2", "5", "8", "10"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:48+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "419", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00103', 'pukao-0c700c30', 'pukao-0c700c30-moex-113-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '在總合供需模型中，若因為中東地區緊張導致原油價格上漲，將使產出 ，實質利率 。', '["上升，上升", "上升，下降", "下降，上升", "下降，下降"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:48+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "419", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL)
